        { grpCd: "SD130", compID: "acb_cnd_ctrtTrfClsCd,acb_ctrtTrfClsCd,gr_item:ctrtTrfClsCd"} //계약요율구분
        ,{ grpCd: "LO124", compID: "acb_anucTrfClsCd,gr_item:anucTrfClsCd"} //고시요율구분
        ,{ grpCd: "LO125", compID: "acb_dcScClssCd,gr_item:dcScClssCd"}     //할인할증분류
