        //,{ grpCd: "FS853", compID: "gr_item:wageAdptPatternCd,acb_wageAdptPatternCd"}            //노임적용유형
    ]

    $c.data.setCommonCode(codeOptions);

	scwin.f_set("ONLOAD");
};

scwin.onUdcCompleted = function() {
    scwin.f_OnLoad();
};

//-------------------------------------------------------------------------
// scwin.name : f_set
// scwin.desc : 화면 open시 초기 데이타 setting
//------------------------------------------------------------------------- 
scwin.f_set = function ( gubun ) {
    switch ( gubun ) {
        case "ONLOAD":      
        	$c.gus.cfDisableKey();
        	ed_cnd_selpchItemCd.focus();
        	$c.gus.cfDisableBtn([btn_save]);
        	break;

        case "RETRIEVE":
            $c.gus.cfEnableAllBtn();
        	break; 	

        case "DELETE":
        	$c.gus.cfDisableBtn();
        	break;    	
	}
};

