scwin.updCheck = async function(){
    if(ds_item.getModifiedJSON().length > 0){
        if(! await $c.win.confirm(MSG_CM_CRM_005)){    //변경사항이 반영되지 않았습니다. 계속 하시겠습니까?
            return false;
        }
    }
    return true;
};

