	}else if(gubun == "U2"){ //상위매출입항목코드
	    $c.gus.cfSetReturnValue(rtnList, scwin.hid_upperSelpchItemCd, ed_upperSelpchItemNm);
	}else if(gubun == "U3"){ //상위노임매출입항목코드
	    $c.gus.cfSetReturnValue(rtnList, scwin.hid_upperWageSelpchItemCd, ed_upperWageSelpchItemNm);	    
	}
*/
};

scwin.udc_comCodeGridCallback = function (rtnList){
console.log("scwin.udc_comCodeGridCallback~~~");
//console.log("scwin.gubun_callback~~~"+scwin.gubun_callback);

	if(scwin.gubun_callback == "D1"){ //매출차변계정코드
		$c.gus.cfSetReturnValue(rtnList, hid_sellDrAcctCd, ed_sellDrAcctNm);
	}else if(scwin.gubun_callback == "C1"){ //매출대변계정코드
	    $c.gus.cfSetReturnValue(rtnList, hid_sellCrAcctCd, ed_sellCrAcctNm);
	}else if(scwin.gubun_callback == "D2"){ //매입차변계정코드
	    $c.gus.cfSetReturnValue(rtnList, hid_pchsDrAcctCd, ed_pchsDrAcctNm);
	}else if(scwin.gubun_callback == "C2"){ //매입대변계정코드
	    $c.gus.cfSetReturnValue(rtnList, hid_pchsCrAcctCd, ed_pchsCrAcctNm);
	}else if(scwin.gubun_callback == "W1"){ //작업단계코드
	    $c.gus.cfSetReturnValue(rtnList, hid_wrkStpCd, ed_wrkStpNm);
